const GAME_PRESET_INDEX = {};
GAME_PRESETS.forEach(g => { GAME_PRESET_INDEX[g.key] = g; });

const GAME_PRESET_GEN_LABELS = {
  1:'Generation I', 2:'Generation II', 3:'Generation III', 4:'Generation IV',
  5:'Generation V', 6:'Generation VI', 7:'Generation VII', 8:'Generation VIII', 9:'Generation IX'
};
// Resolves a display label for any generation number, including custom generations
// that fall outside the known roman-numeral map above.
function gamePresetGenLabel(gen){
  return GAME_PRESET_GEN_LABELS[gen] || ('Generation ' + gen);
}

const GAME_PRESET_NAME_LOOKUP = {};
GAME_PRESETS.forEach(g => {
  GAME_PRESET_NAME_LOOKUP[normalizeGameNameForMatch(g.label)] = g.key;
});

// Normalizes a typed game name (case, punctuation, "Pokémon"/"Pokemon" prefix)
// for matching against GAME_PRESET_NAME_LOOKUP.
function normalizeGameNameForMatch(s){
  return String(s || '')
    .toLowerCase()
    .replace(/^pok[eé]mon:?\s*/, '')
    .replace(/[:!,'’]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// Attempts to resolve a free-typed game name/tag to a known preset key.
function detectGameKeyFromTag(tag){
  const key = GAME_PRESET_NAME_LOOKUP[normalizeGameNameForMatch(tag)];
  return key || null;
}
